-- ----------------------------
-- Triggers structure for table jingju
-- ----------------------------
DROP TRIGGER IF EXISTS `update_cabinet_quantity_after_insert`;
delimiter ;;
CREATE TRIGGER `update_cabinet_quantity_after_insert` AFTER INSERT ON `jingju` FOR EACH ROW BEGIN
    UPDATE jingjucabinet
    SET quantity = (SELECT COUNT(*) FROM jingju WHERE cabinet = NEW.cabinet)
    WHERE id = NEW.cabinet;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table jingju
-- ----------------------------
DROP TRIGGER IF EXISTS `update_cabinet_quantity_after_update`;
delimiter ;;
CREATE TRIGGER `update_cabinet_quantity_after_update` AFTER UPDATE ON `jingju` FOR EACH ROW BEGIN
    IF NEW.cabinet != OLD.cabinet THEN
        -- 更新旧柜子的数量
        UPDATE jingjucabinet
        SET quantity = (SELECT COUNT(*) FROM jingju WHERE cabinet = OLD.cabinet)
        WHERE id = OLD.cabinet;
        
        -- 更新新柜子的数量
        UPDATE jingjucabinet
        SET quantity = (SELECT COUNT(*) FROM jingju WHERE cabinet = NEW.cabinet)
        WHERE id = NEW.cabinet;
    END IF;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table jingju
-- ----------------------------
DROP TRIGGER IF EXISTS `update_cabinet_quantity_after_delete`;
delimiter ;;
CREATE TRIGGER `update_cabinet_quantity_after_delete` AFTER DELETE ON `jingju` FOR EACH ROW BEGIN
    UPDATE jingjucabinet
    SET quantity = (SELECT COUNT(*) FROM jingju WHERE cabinet = OLD.cabinet)
    WHERE id = OLD.cabinet;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table jingjucabinet
-- ----------------------------
DROP TRIGGER IF EXISTS `update_jingjucabinet_status`;
delimiter ;;
CREATE TRIGGER `update_jingjucabinet_status` BEFORE UPDATE ON `jingjucabinet` FOR EACH ROW BEGIN
    -- 当quantity大于capacity的4/5时，status改为2
    IF NEW.quantity > (NEW.capacity * 4 / 5) THEN
        SET NEW.status = 2;
    -- 当quantity小于capacity的1/5时，status改为0
    ELSEIF NEW.quantity < (NEW.capacity * 1 / 5) THEN
        SET NEW.status = 0;
    -- 其他情况，status默认为1
    ELSE
        SET NEW.status = 1;
    END IF;
END
;;
delimiter ;

-- ----------------------------
-- Triggers structure for table returnjingju
-- ----------------------------
DROP TRIGGER IF EXISTS `set_gettime_on_insert`;
delimiter ;;
CREATE TRIGGER `set_gettime_on_insert` BEFORE INSERT ON `returnjingju` FOR EACH ROW BEGIN
    SET NEW.gettime = DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%s');
END
;;
delimiter ;

